'use client'
import { useAuthStore } from '../../../store/authStore'
import Card from '../../../components/ui/Card'
import Badge from '../../../components/ui/Badge'
import {
  FileText,
  FolderOpen,
  MessageSquare,
  Clock,
  CheckCircle,
  AlertCircle,
  ChevronRight,
} from 'lucide-react'
import Link from 'next/link'

// Quick stats data (will come from API later)
const stats = [
  {
    label:   'Active Applications',
    value:   '3',
    icon:    FileText,
    color:   'bg-blue-50 text-blue-700',
    border:  'border-blue-100',
  },
  {
    label:   'Documents Uploaded',
    value:   '8',
    icon:    FolderOpen,
    color:   'bg-green-50 text-green-700',
    border:  'border-green-100',
  },
  {
    label:   'Pending Grievances',
    value:   '1',
    icon:    MessageSquare,
    color:   'bg-orange-50 text-orange-700',
    border:  'border-orange-100',
  },
  {
    label:   'Days to SLA Deadline',
    value:   '12',
    icon:    Clock,
    color:   'bg-red-50 text-red-700',
    border:  'border-red-100',
  },
]

// Recent applications (will come from API later)
const recentApplications = [
  {
    id:       1,
    scheme:   'Disability Pension',
    status:   'under_review' as const,
    date:     '10 Mar 2026',
    badgeColor: 'yellow' as const,
    badgeLabel: 'Under Review',
  },
  {
    id:       2,
    scheme:   'ECHS Medical Card',
    status:   'approved' as const,
    date:     '28 Feb 2026',
    badgeColor: 'green' as const,
    badgeLabel: 'Approved',
  },
  {
    id:       3,
    scheme:   'Education Scholarship',
    status:   'submitted' as const,
    date:     '15 Feb 2026',
    badgeColor: 'blue' as const,
    badgeLabel: 'Submitted',
  },
]

// Quick action buttons
const quickActions = [
  {
    href:  '/benefits/apply',
    label: 'Apply for Benefit',
    icon:  FileText,
    color: 'bg-green-700 hover:bg-green-800 text-white',
  },
  {
    href:  '/documents',
    label: 'Upload Document',
    icon:  FolderOpen,
    color: 'bg-blue-600 hover:bg-blue-700 text-white',
  },
  {
    href:  '/grievances/new',
    label: 'File Grievance',
    icon:  MessageSquare,
    color: 'bg-orange-500 hover:bg-orange-600 text-white',
  },
  {
    href:  '/assistant',
    label: 'Ask AI Assistant',
    icon:  AlertCircle,
    color: 'bg-purple-600 hover:bg-purple-700 text-white',
  },
]

export default function DashboardPage() {
  const { user } = useAuthStore()

  return (
    <div className="space-y-6">

      {/* Welcome banner */}
      <div className="bg-linear-to-r from-green-700 to-green-600 rounded-2xl p-6 text-white">
        <h2 className="text-2xl font-bold mb-1">
          Welcome, {user?.full_name?.split(' ')[0] ?? 'Veteran'} 🎖️
        </h2>
        <p className="text-green-100 text-sm">
          Your unified benefits portal — track applications, upload documents, and get help.
        </p>
      </div>

      {/* Stats row */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {stats.map((stat) => {
          const Icon = stat.icon
          return (
            <Card key={stat.label} padding="md">
              <div className="flex items-center gap-3">
                <div className={`p-2.5 rounded-xl ${stat.color}`}>
                  <Icon size={20} />
                </div>
                <div>
                  <p className="text-2xl font-bold text-gray-900">{stat.value}</p>
                  <p className="text-xs text-gray-500 leading-tight">{stat.label}</p>
                </div>
              </div>
            </Card>
          )
        })}
      </div>

      {/* Quick actions */}
      <div>
        <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-3">
          Quick Actions
        </h3>
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          {quickActions.map((action) => {
            const Icon = action.icon
            return (
              <Link
                key={action.href}
                href={action.href}
                className={`flex items-center gap-3 px-4 py-3 rounded-xl font-medium text-sm transition-all ${action.color}`}
              >
                <Icon size={18} />
                {action.label}
              </Link>
            )
          })}
        </div>
      </div>

      {/* Recent applications */}
      <div>
        <div className="flex items-center justify-between mb-3">
          <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider">
            Recent Applications
          </h3>
          <Link
            href="/benefits"
            className="text-xs text-green-700 font-semibold hover:underline flex items-center gap-1"
          >
            View all <ChevronRight size={14} />
          </Link>
        </div>

        <Card padding="none">
          <div className="divide-y divide-gray-100">
            {recentApplications.map((app) => (
              <Link
                key={app.id}
                href={`/benefits/${app.id}`}
                className="flex items-center justify-between px-5 py-4 hover:bg-gray-50 transition-colors"
              >
                <div className="flex items-center gap-3">
                  <div className="w-9 h-9 bg-green-50 rounded-lg flex items-center justify-center">
                    <FileText size={16} className="text-green-700" />
                  </div>
                  <div>
                    <p className="text-sm font-semibold text-gray-800">{app.scheme}</p>
                    <p className="text-xs text-gray-400">{app.date}</p>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <Badge label={app.badgeLabel} color={app.badgeColor} />
                  <ChevronRight size={16} className="text-gray-400" />
                </div>
              </Link>
            ))}
          </div>
        </Card>
      </div>

      {/* Blockchain verified notice */}
      <Card padding="md" className="border-green-100 bg-green-50">
        <div className="flex items-center gap-3">
          <CheckCircle size={22} className="text-green-700 shrink-0" />
          <div>
            <p className="text-sm font-semibold text-green-800">
              Blockchain Verified Portal
            </p>
            <p className="text-xs text-green-600 mt-0.5">
              All your documents and application records are secured and verified on the blockchain.
            </p>
          </div>
        </div>
      </Card>

    </div>
  )
}